          { e: "😊", n: "Customer", d: "NPS, customer complaint resolution, digital adoption, market share — 'How do customers see us?'" },
          { e: "⚙️", n: "Internal Process", d: "Credit TAT, loan processing errors, branch productivity, fraud incidents — 'What must we excel at?'" },
          { e: "🌱", n: "Learning & Growth", d: "JAIIB/CAIIB completion rate, training hours, employee engagement score, succession readiness — 'Can we continue to improve?'" }
