          { e: "👔", n: "M: Management", d: "Board governance, risk appetite adherence, compliance culture, internal audit effectiveness, whistle-blower mechanism, succession" },
          { e: "📈", n: "E+L+S", d: "E: ROA, NIM, cost-income; L: LCR, NSFR, interbank dependence; S: AFS/HFT losses, interest rate risk (DV01), forex open position" }
